import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  LogOut,
  Home,
  User,
  Calendar,
  Users,
  MessageCircle,
  Briefcase,
  GraduationCap,
  Newspaper,
  Settings,
  Award,
  Heart,
  BookOpen,
  TrendingUp,
  Users2,
  Calendar as CalendarIcon,
  Zap,
  Bell,
} from "lucide-react";
import { useAuth } from "./AuthContext";

export default function Dashboard() {
  const navigate = useNavigate();
  const { user, logout, loading } = useAuth();
  const [stats, setStats] = useState({
    connections: 0,
    events: 0,
    jobs: 0,
    messages: 0,
  });

  useEffect(() => {
    // Animate stats on mount
    if (user) {
      const timer = setTimeout(() => {
        setStats({
          connections: user.connections || 142,
          events: 5,
          jobs: 28,
          messages: 3,
        });
      }, 300);
      return () => clearTimeout(timer);
    }
  }, [user]);

  const handleLogout = () => {
    logout();
    navigate("/");
  };

  const menuItems = [
    {
      label: "Profile",
      path: "/profile",
      icon: User,
      color: "from-blue-500 to-blue-600",
    },
    {
      label: "Events",
      path: "/events",
      icon: Calendar,
      color: "from-green-500 to-green-600",
    },
    {
      label: "Network",
      path: "/network",
      icon: Users,
      color: "from-purple-500 to-purple-600",
    },
    {
      label: "Messages",
      path: "/messages",
      icon: MessageCircle,
      color: "from-pink-500 to-pink-600",
    },
    {
      label: "Jobs",
      path: "/jobs",
      icon: Briefcase,
      color: "from-orange-500 to-orange-600",
    },
    {
      label: "Directory",
      path: "/directory",
      icon: GraduationCap,
      color: "from-indigo-500 to-indigo-600",
    },
    {
      label: "News",
      path: "/news",
      icon: Newspaper,
      color: "from-red-500 to-red-600",
    },
    {
      label: "Mentorship",
      path: "/mentorship",
      icon: BookOpen,
      color: "from-cyan-500 to-cyan-600",
    },
    {
      label: "Volunteer",
      path: "/volunteer",
      icon: Heart,
      color: "from-rose-500 to-rose-600",
    },
    {
      label: "Scholarships",
      path: "/scholarships",
      icon: Award,
      color: "from-yellow-500 to-yellow-600",
    },
    {
      label: "Testimonials",
      path: "/testimonials",
      icon: Users2,
      color: "from-violet-500 to-violet-600",
    },
    {
      label: "Settings",
      path: "/settings",
      icon: Settings,
      color: "from-slate-500 to-slate-600",
    },
  ];

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-gray-900 to-gray-800 flex items-center justify-center">
        <div className="text-center">
          <Zap className="w-12 h-12 text-blue-500 animate-spin mx-auto mb-4" />
          <p className="text-white text-lg font-semibold">
            Loading your dashboard...
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100">
      {/* Navbar */}
      <nav className="bg-white shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-br from-blue-600 to-purple-600 rounded-xl flex items-center justify-center">
              <Zap className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-2xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
              Alumni Network
            </h1>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center gap-3 px-4 py-2 bg-blue-50 rounded-lg">
              <span className="text-gray-700 font-semibold">{user?.email}</span>
            </div>
            <button
              onClick={handleLogout}
              className="flex items-center gap-2 text-red-600 hover:text-red-700 hover:bg-red-50 px-4 py-2 rounded-lg transition font-semibold"
            >
              <LogOut className="w-5 h-5" /> Logout
            </button>
          </div>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Welcome Section */}
        <div className="mb-12">
          <h2 className="text-4xl font-bold text-gray-900 mb-2">
            Welcome back,{" "}
            <span className="bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
              {user?.name}
            </span>
            !
          </h2>
          <p className="text-gray-600 flex items-center gap-2">
            <Bell className="w-5 h-5 text-blue-500" />
            You have 3 unread messages
          </p>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          {[
            {
              label: "Connections",
              value: stats.connections,
              icon: Users,
              color: "from-blue-500 to-blue-600",
            },
            {
              label: "Upcoming Events",
              value: stats.events,
              icon: CalendarIcon,
              color: "from-green-500 to-green-600",
            },
            {
              label: "Job Opportunities",
              value: stats.jobs,
              icon: Briefcase,
              color: "from-orange-500 to-orange-600",
            },
            {
              label: "Messages",
              value: stats.messages,
              icon: MessageCircle,
              color: "from-pink-500 to-pink-600",
            },
          ].map((stat, idx) => {
            const Icon = stat.icon;
            return (
              <div
                key={idx}
                className="bg-white rounded-2xl shadow-lg p-6 hover:shadow-xl transition-all duration-300 hover:scale-105"
              >
                <div
                  className={`inline-flex items-center justify-center w-12 h-12 bg-gradient-to-br ${stat.color} rounded-lg mb-4`}
                >
                  <Icon className="w-6 h-6 text-white" />
                </div>
                <p className="text-gray-600 text-sm font-medium mb-1">
                  {stat.label}
                </p>
                <p className="text-4xl font-bold text-gray-900">{stat.value}</p>
              </div>
            );
          })}
        </div>

        {/* Menu Grid */}
        <div className="mb-12">
          <h3 className="text-2xl font-bold text-gray-900 mb-6">
            Quick Access
          </h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            {menuItems.map((item) => {
              const IconComponent = item.icon;
              return (
                <button
                  key={item.path}
                  onClick={() => navigate(item.path)}
                  className="group bg-white rounded-2xl shadow-md p-6 hover:shadow-xl transition-all duration-300 hover:scale-105 text-left"
                >
                  <div
                    className={`inline-flex items-center justify-center w-12 h-12 bg-gradient-to-br ${item.color} rounded-xl mb-4 group-hover:scale-110 transition-transform`}
                  >
                    <IconComponent className="w-6 h-6 text-white" />
                  </div>
                  <h4 className="font-semibold text-gray-900 mb-1">
                    {item.label}
                  </h4>
                  <p className="text-gray-600 text-sm">
                    Explore {item.label.toLowerCase()}
                  </p>
                </button>
              );
            })}
          </div>
        </div>

        {/* Featured Section */}
        <div className="bg-gradient-to-r from-blue-600 to-purple-600 rounded-3xl shadow-2xl p-8 text-white">
          <div className="flex items-center justify-between mb-4">
            <div>
              <h3 className="text-2xl font-bold mb-2">Upgrade to Premium</h3>
              <p className="text-blue-100">
                Get exclusive access to premium features and events
              </p>
            </div>
            <Zap className="w-12 h-12 text-yellow-300" />
          </div>
          <button className="bg-white text-blue-600 px-6 py-3 rounded-lg font-semibold hover:bg-blue-50 transition">
            Learn More
          </button>
        </div>
      </div>
    </div>
  );
}
